external_knowledge:
- "Long hauls" refers to routes with distances greater than 5 miles;
- "Finished within the lunch break" implies an estimated travel time of less than 45 minutes, assuming a standard lunch break duration;
- "Logistics manager" is associated with the user_id of 0 in the database.

sql:
SELECT MIN(actual_travel_time) AS lowest_actual_travel_time
FROM routes
WHERE status = 'active';

SELECT 
  (SELECT COUNT(*) FROM routes) AS total_routes, 
  (SELECT COUNT(*) FROM users) AS total_users;

SELECT route_id 
FROM routes 
WHERE route_type_id = (SELECT type_id FROM route_types WHERE type_name = 'pickup');

SELECT SUM(CAST(REPLACE(estimated_travel_time, ' hours', '') AS REAL)) AS total_estimated_travel_time
FROM routes
WHERE route_type_id = (SELECT type_id FROM route_types WHERE type_name = 'delivery');

SELECT COUNT(*) 
FROM route_access 
WHERE user_id = 1;
